    //根据文件类型，细化处理
    static build_children(that, list, parentName) {
        const folderList = [];
        const linkList = [];
        const fileList = [];
        const blockList = [];
        const characterList = [];
        const pipeList = [];
        const socketsList = [];
        // console.log(list)
        for (const entry of list) {
            if (settings_1.Settings.ShowHiddenFilesAndFolders == false && entry.name.indexOf(".") == 0) {
                continue;
            }
            if (entry.type == "d") {
                // 盘符正则
                const reg = /^\/([A-Z]):\/$/;
                const flag = reg.test(parentName);
                if (settings_1.Settings.ShowHiddenFilesAndFolders == false && flag &&
                    (entry.name == "$Recycle.Bin" ||
                        entry.name == "$RECYCLE.BIN" ||
                        entry.name == "System Volume Information")) {
                    continue;
                }
                folderList.push(new ftpFolderNode_1.FTPFolderNode(that.info, that.viewType, entry.name, entry, parentName));
            }
            else if (entry.type == "l") {
                if (entry.name.indexOf(".") != -1) {
                    fileList.push(new ftpFileNode_1.FTPFileNode(that.info, that.viewType, entry, parentName));
                }
                else {
                    linkList.push(new ftpLinkNode_1.FTPLinkNode(that.info, that.viewType, entry.name, entry, parentName));
                }
            }
            else if (entry.type == "b") {
                blockList.push(new ftpBlockNode_1.FTPBlockNode(that.info, entry, parentName));
            }
            else if (entry.type == "c") {
                characterList.push(new ftpCharacterNode_1.FTPCharacterNode(that.info, entry, parentName));
            }
            else if (entry.type == "p") {
                pipeList.push(new ftpPipeNode_1.FTPPipeNode(that.info, entry, parentName));
            }
            else if (entry.type == "s") {
                socketsList.push(new ftpSocketsNode_1.FTPSocketskNode(that.info, entry, parentName));
            }
            else {
                fileList.push(new ftpFileNode_1.FTPFileNode(that.info, that.viewType, entry, parentName));
            }
        }
        const fileArr = [].concat(fileList)
            .concat(blockList)
            .concat(socketsList)
            .concat(characterList)
            .concat(pipeList)
            .sort((a, b) => a.file.name.localeCompare(b.file.name));
        const folderArr = [].concat(folderList)
            .concat(linkList)
            .sort((a, b) => a.name.localeCompare(b.name));
        return [].concat(folderArr).concat(fileArr);
    }
